#!/usr/bin/env python3
import sys
import xml.etree.ElementTree as ET


def parse_deployment_config(path: str) -> dict[str, str | None]:
    tree = ET.parse(path)
    root = tree.getroot()
    return {item.get('name', ''): item.text for item in root.findall('.//setting')}


if __name__ == '__main__':
    for key, value in parse_deployment_config(sys.argv[1]).items():
        print(f'{key}={value or ""}')
